#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-29

# test-shared-scripts-drift.sh — asserts src/skills/_shared/ files are in sync
# with their consumer copies. Catches hand-edits before they become silent
# drift across the duplicates.
#
# Background: render-spec.mjs is consumed by /ork:explore + /ork:assess. Each
# skill needs its own copy on disk because the plugin-build pipeline does
# `cp -R src/skills/`. To prevent drift the canonical copy lives in
# src/skills/_shared/ and `scripts/sync-shared-scripts.sh` propagates it.

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"

echo "Shared scripts drift check"
echo

PASS=0
FAIL=0

# Positive case: --check should pass when sources are in sync
if bash "$PROJECT_ROOT/scripts/sync-shared-scripts.sh" --check >/dev/null 2>&1; then
  echo "  PASS in-sync sources pass --check"
  PASS=$((PASS + 1))
else
  echo "  FAIL in-sync sources should pass --check (run: bash scripts/sync-shared-scripts.sh)"
  FAIL=$((FAIL + 1))
fi

# Negative case: introduce drift in a copy, --check must catch it; restore + verify
CONSUMER="$PROJECT_ROOT/src/skills/explore/scripts/render-spec.mjs"
if [[ -f "$CONSUMER" ]]; then
  BACKUP="$(mktemp)"
  cp "$CONSUMER" "$BACKUP"
  trap 'cp "$BACKUP" "$CONSUMER"; rm -f "$BACKUP"' EXIT
  echo "// drift injected by test" >> "$CONSUMER"
  if ! bash "$PROJECT_ROOT/scripts/sync-shared-scripts.sh" --check >/dev/null 2>&1; then
    echo "  PASS --check correctly rejects drift"
    PASS=$((PASS + 1))
  else
    echo "  FAIL --check did not detect drift"
    FAIL=$((FAIL + 1))
  fi
  cp "$BACKUP" "$CONSUMER"
  if bash "$PROJECT_ROOT/scripts/sync-shared-scripts.sh" --check >/dev/null 2>&1; then
    echo "  PASS post-restore back to in-sync"
    PASS=$((PASS + 1))
  else
    echo "  FAIL post-restore did not return to in-sync (test setup bug)"
    FAIL=$((FAIL + 1))
  fi
else
  echo "  SKIP consumer not found at expected path"
fi

echo
echo "─── Results ───"
echo "  PASS: $PASS"
echo "  FAIL: $FAIL"

if [[ $FAIL -gt 0 ]]; then
  exit 1
fi
exit 0
